SELECT COUNT(DISTINCT package_id) AS package_count
FROM remote_licenses
WHERE license_type IN ('BSD 3-clause "New" License', 'BSD 3-clause "Revised" License');

SELECT COUNT(*) AS total_checks
FROM license_compliance_checks
WHERE package_id = 1;

SELECT COUNT(package_id) 
FROM project_packages 
WHERE project_id = 1;

SELECT u.user_name, u.email
FROM users u
WHERE u.role = 'developer' AND u.user_id IN (
  SELECT DISTINCT user_id
  FROM user_access_logs
);
